INSERT INTO macros (name, content, category, sort_order) VALUES
('첫인사', '안녕하세요, 커버링 입니다.', '기본 인사', 1),
('문의사항', E'안녕하세요, 커버링 입니다.\n문의 내용을 보다 자세하게 작성해 주시면 확인 후 안내드리겠습니다.', '기본 인사', 2),
('확인필요', E'안녕하세요, 커버링 입니다.\n문의주신 내용 확인 후 답변 드리도록 하겠습니다.\n잠시만 기다려주세요 :)', '기본 인사', 3),
('운영시간', E'안녕하세요, 커버링 입니다.\n커버링 1:1 문의 운영시간은 오전 10시~ 오후 10시까지 진행되며,\n운영시간 외에 남겨주시는 문의는 순차적으로 확인하여 답변 드리고 있습니다.\n이용에 참고 부탁드립니다.', '기본 인사', 4),
('유선상담', E'안녕하세요, 커버링입니다.\n\n현재 유선상담은 지원되고 있지 않은 점 양해 부탁드립니다.\n문의사항이 있으시다면 지금과 같이 채팅으로 말씀해 주세요.\n확인 후 빠르게 안내드리겠습니다 : )', '기본 인사', 5),
('수거가능', E'안녕하세요, 커버링입니다.\n\n해당 품목 또한 배출 방법에 맞게 커버링 봉투에 담거나 아무 봉투에 "커버링 수거"라는 메모를 작성한 후,\n봉투를 묶어서 배출해주시면 원활히 수거 가능합니다 :)', '기본 인사', 6),
('마무리', E'감사합니다.\n\n언제나 더 나은 서비스를 드릴 수 있도록 노력하는 커버링이 되겠습니다 :)', '기본 인사', 7),
('마무리인사', E'감사합니다!\n\n남은 하루도 평안하고 행복하게 보내시기 바라며,\n추가 문의가 있으시다면 언제든지 문의 주시기 바랍니다 :)', '기본 인사', 8),
('미회신종료안내', '*별도의 회신이 없을 경우, 상담이 종료됩니다.', '기본 인사', 9),
('오류확인', E'안녕하세요, 커버링 입니다.\n\n남겨주신 내용 확인하였으나, 오류 여부를 판단하기 어려운 상태입니다 :(\n번거로우시겠지만 면밀한 파악을 위해 아래 내용 작성 부탁드립니다.\n\n폰 기종 :\n앱 업데이트 여부 :\n확인되는 현상 (사진, 영상 등) : \n*시간까지 확인되어야 합니다.', '기본 인사', 10),
('카드등록오류확인', E'안녕하세요, 커버링 입니다.\n먼저 하기 전달드리는 내용으로 확인 부탁드립니다.\n\n1 ) 이용 가능한 카드인지 ( 분실신고, 정지, 잔액부족 확인 )\n2 ) 법인카드인지\n3 ) 생년월일 6자 기재했는지\n\n위 내용에 해당하지 않음에도 문제가 발생하고 있다면, 확인되는 오류 문구 전달 부탁드립니다.', '기본 인사', 11),
('죄송_첫이용봉투미지급', E'안녕하세요, 커버링 입니다.\n\n서비스 이용에 불편 드려 죄송합니다.\n\n처음 신청해 주신 봉투를 다시 무료로 받아보실 수 있도록 기 접수건 취소해 드렸습니다.\n매우 번거로우시겠지만, 아래 과정으로 재 신청 부탁 드립니다.\n\n1. 커버링 앱 > [봉투 구매] 버튼 클릭\n2. 원하시는 구매 수량 선택 > 구매하기 버튼 클릭\n3. 배송 요청사항 & 받는 사람 정보 입력 > 쿠폰 적용 > 결제 완료\n\n신청하신 봉투는 최대 3일 정도 소요되는 점 참고 부탁 드립니다.\n\n\n** 참고로 다른 봉투 사용 후 ''커버링 수거'' 메모 부착해 배출해 주셔도 수거 가능합니다.\n빠른 수거를 희망하신다면, 다른 봉투를 사용하여 배출해 주셔도 괜찮습니다.\n\n단,\n1. 손잡이 있는 봉투에 담아서 입구를 묶어주시고\n2. 너무 얇아 찢어질 위험이 있거나, 물 흐름이 존재하는 경우는 수거가 어렵습니다.', '기본 인사', 12),
('죄송_기본봉투미지급', E'안녕하세요, 커버링입니다.\n\n먼저 이용에 불편을 드리게 되어 죄송합니다.\n문의주신 내용을 확인해보니, 해당 건은 기사님의 착오로 인해 기본 봉투가 미지급 된 것으로 보입니다.\n\n우선은 일반 폐기물은 커버링 지급 봉투가 아닌 다른 봉투에 배출 품목을 담아 ''커버링 수거'' 메모 부착하여 배출해 주셔도 원활히 수거 가능합니다.\n혹시 급하게 수거가 필요하시다면, 해당 형태로 배출 후 수거 신청 부탁드립니다.\n\n아울러 수거 신청하실 때, "수거 후 무료 봉투는 안 주셔도 돼요" 체크 해제 여부 꼭 확인해 주세요!\n기존처럼 체크 해제 후 신청 주시면, 이번에는 문제 없이 지급될 수 있도록 하겠습니다.\n\n\n또는 고객님께서 봉투를 무료 배송으로 받아보실 수 있도록 ''기본 요금 무료'' 쿠폰을 지급 드렸습니다. ( 80L: 300원 / 150L: 1,000원 )\n혹시라도 필요하시다면 아래 과정으로 구입 부탁 드립니다.\n\n1. 커버링 앱 > [봉투 구매] 버튼 클릭\n2. 원하시는 구매 수량 선택 > 구매하기 버튼 클릭\n3. 배송 요청사항 & 받는 사람 정보 입력 > 쿠폰 적용 > 결제 완료\n\n구매하신 봉투는 배송까지 최대 3일 정도 소요되는 점 참고 부탁 드립니다.', '기본 인사', 13),
('죄송_미배출여부확인', E'안녕하세요, 커버링입니다.\n\n서비스 이용에 불편을 드려 죄송합니다.\n내용 확인해 본 결과, 기사님이 해당 위치에 방문하신 것으로 확인되는데 전달 드린 이미지 내 위치가 맞는지\n확인해 주시면 추가 안내 드리도록 하겠습니다.', '기본 인사', 14),
('죄송_수거지연문의', E'안녕하세요, 커버링 입니다.\n\n이용에 불편을 드려 정말 죄송합니다.\n\n수거는 보통 오후 10시부터 오전 6시 사이에 마무리되고 있지만,\n최근 신청량이 많아 일부 지역에서는 수거가 조금 늦어지는 경우가 있습니다.\n\n안내드린 시간보다 배출품이 오래 머물러 많이 불편하셨을 거라 생각합니다.\n말씀 주신 부분은 내부적으로 확인해, 앞으로는 더 원활하게 수거가 진행될 수 있도록 개선하겠습니다.\n\n현재 해당 배출품은 정상적으로 수거가 완료되었음을 안내드립니다.\n이용에 불편을 드려 다시 한 번 죄송합니다.\n\n감사합니다.', '기본 인사', 16);
INSERT INTO macros (name, content, category, sort_order) VALUES
('정책미준수_무게초과', E'안녕하세요, 커버링 입니다.\n\n확인 결과, 해당 건은 봉투 당 무게가 초과되어 수거 실패 되었습니다.\n1개의 봉투 당 15kg 미만으로 배출해 주셔야 원활하게 수거가 가능합니다.\n번거로우시겠지만, 해당 봉투를 2개로 나누어 재신청 및 배출해 주시면 감사하겠습니다.\n\n더 나은 서비스 제공을 위해 노력하겠습니다. 감사합니다.', '정책/수거이슈', 1),
('정책미준수_25kg무게초과', E'안녕하세요, 커버링 입니다.\n\n해당 봉투는 폐기물 포함하시면 최대 25kg 까지만 배출이 가능합니다.\n\n그러나 해당 주문 확인 시, 25kg 초과하여 수거가 어려웠던 것으로 확인됩니다.\n\n이처럼 150L 봉투를 기준으로, 25kg 를 초과하는 경우에는 수거 진행이 어렵기 때문에\n\n다른 봉투 혹은 80L 봉투에 나누어 담아주시기 바랍니다.\n\n감사합니다.', '정책/수거이슈', 2),
('정책미준수_물흐름', E'안녕하세요, 커버링입니다.\n\n서비스 이용에 불편을 드려 죄송합니다.\n확인 결과, 기사님이 안내해 주신 위치까지 방문하였으나 물흐름으로 인해 수거가 이루어지지 않은 것으로 확인되었습니다.\n앱 내 이용방법 안내와 같이, 공용공간 오염 등을 방지하기 위해 물흐름이 있는 경우 수거가 진행되지 않는 점 양해 부탁드립니다.\n물흐름이 발생하지 않도록 조치하여 다시 수거 신청해 주시면 문제 없이 수거 가능하니 참고 부탁드립니다.\n\n더 나은 서비스 제공을 위해 노력하겠습니다.\n감사합니다.', '정책/수거이슈', 3),
('수거경험혼동', E'안녕하세요, 커버링입니다.\n\n이용에 혼선을 드려 죄송합니다.\n확인 결과, 이번 건은 정상적인 수거 기준에 부합하지 않아 수거가 어려운 상황이었습니다.\n\n커버링 수거는 아래 기준에 따라 진행되고 있습니다.\n\n1. 커버링 봉투로 배출 → 수거 가능\n2. ''커버링 수거'' 메모가 적힌 봉투로 배출 → 수거 가능\n3. 메모는 없지만, 배출 품목 이미지 사진을 업로드한 경우 → 수거 가능\n4. 위 조건 중 어느 것도 해당되지 않는 경우 → 수거 불가\n\n앞으로 기존처럼 배출을 원하신다면,\n수거 신청 후 배출 품목 이미지를 꼭 업로드해 주시면 감사하겠습니다.', '정책/수거이슈', 4),
('고객불만_배차변동안내', E'참고로 수거 신청 건 마다 배차되는 기사님이 달라집니다.\n이에 따라 해당 주소지를 자주 방문해 주신 기사님은 사소한 부분은 감안하여 잘 수거해 주시는 경우가 있지만, 판단에 어려움이 있어 매뉴얼을 정확히 지켜 수거해 주시는 기사님도 계십니다.\n\n너른 마음으로 양해 부탁 드리며, 번거로우시겠지만 앞으로도 원활한 수거 진행을 위해 정확한 주소/ 출입정보/ 요청사항 기재를 부탁드립니다.', '정책/수거이슈', 5),
('정책미준수_커버링봉투아님', E'안녕하세요, 커버링입니다.\n\n최근 수거 진행 시 오인수거가 빈번하게 발생하고 있습니다.\n이를 방지하기 위해 커버링 봉투 또는 "커버링 수거" 메모가 부착된 봉투만 수거하며,\n신청 시 입력하신 배출 수량과 실제 배출된 봉투 개수를 확인한 후 일치하는 건에 한해 수거가 진행됩니다.\n\n보다 안전하고 정확한 수거를 위한 조치이오니, 이용 시 참고 부탁드립니다.', '정책/수거이슈', 6),
('정책미준수_출입실패', E'안녕하세요, 커버링 입니다.\n\n해당 주문건 확인해 보니, 아래 사유로 인해 출입 실패 된 것으로 확인됩니다.\n\n사유 : 출입문 비밀번호가 맞지않음\n\n혹시 종 모양 버튼이나 열쇠 버튼 등이 존재했을까요?\n\n만일 종 모양 버튼, 열쇠 모양 버튼, 호출 버튼 등이 있다면\n해당 버튼까지 모두 기재해 주셔야 하는 점 참고 부탁드립니다.', '정책/수거이슈', 7),
('출입실패_경비실미응답', E'안녕하세요, 커버링 입니다.\n\n이번 주문건의 경우, 아래 사유로 인해 출입 실패 된 것으로 확인됩니다.\n\n사유 : 경비실이 응답하지 않습니다\n\n혹시 경비실 호출 외에 다른 출입 방법은 없을까요?\n다른 방법으로 출입이 가능하다면, 경비실 호출 실패했을 때를 대비할 수 있도록\n출입 방법에 함께 기재해 주시면 감사드리겠습니다.', '정책/수거이슈', 8),
('정책_물맺힘', E'안녕하세요, 커버링 입니다. \n\n단순 물맺힘 일 경우, 수거 신청 시 요청사항에 냉동 등으로 인한 단순 물맺힘이니 수거 진행해도 괜찮다는 내용 기재해주시면\n문제없이 수거가 가능합니다 :)', '정책/수거이슈', 9),
('이용방법_수거품목', E'안녕하세요, 커버링 입니다.\n수거 가능한 품목 관련해 문의 주신 내용 확인했습니다.\n\n참고로 [ 화재 위험이 있는 제품 / 의약품 / 산업 폐기물 ] 을 제외한 대부분의 생활 폐기물은 수거 가능합니다.\n\n배출하실 물품은 모두 손잡이가 있는 봉투에 담아 입구를 묶어주시고, 1봉투당 15kg 미만으로 배출해 주세요! \n** 봉투 당 15kg 초과 시에는 수거가 어려워 여러 봉투로 나누어 담아주셔야 합니다.\n\n아래는 품목별로 안내드리는 수거 기준입니다.\n\n[품목별 안내]\n음식물, 액체류 (물 흐름 가능성이 있는 경우) → 비닐봉투 등으로 한 번 더 밀봉 후 배출\n냉동 식품 → 물 맺힘이 발생하면 물 흐름으로 수거 실패 될 수 있어, 비닐 봉투 등으로 한번 더 밀봉 + 요청 사항에 기재하기\n봉투에 들어가기 어려운 크기나 모양의 품목 (대형 폐기물) → 가능한 한 분해하여 봉투 안에 담거나 150L 봉투 사용 또는 "커버링 방문수거" 이용하기\n날카로운 물품, 깨질 수 있는 품목 → 신문지나 두꺼운 쇼핑백 등으로 감싸서 안전하게 배출\n종이박스류 → 내용물을 비운 뒤 펼쳐서 봉투 옆에 두기\n(단, 펼치기 어려운 작은 박스는 봉투 안에 함께 담아주세요)\nPP박스 → 내용물을 비운 뒤 펼쳐서 끈으로 묶은 뒤, 봉투 옆에 두기\n\n\n보다 안전하고 원활한 수거를 위해 위 사항 참고 부탁드립니다.\n\n감사합니다.', '정책/수거이슈', 10),
('이용방법_주문번호확인', E'주문번호는 [이용내역 > 수거 건 선택 > 수거 상세 페이지] 에 적힌 영/숫자 혼합 8자리 전달 주시면 됩니다.\n아직 신청 건이 없으시다면 앱 내에서 수거 신청 하신 후에 확인 부탁드립니다.', '정책/수거이슈', 11),
('이용방법_주문취소수정', E'안녕하세요, 커버링 입니다. \n\n앱 내 [이용내역 > 수거 건 선택 > 수거 상세페이지] 에서 주문 수정/취소 가능합니다.\n이용에 참고 부탁드립니다.\n\n감사합니다 :)', '정책/수거이슈', 12),
('이용방법_봉투구매방법', E'안녕하세요, 커버링 입니다.\n\n수거 없이 커버링 봉투만 구매를 원하시는 경우,\n앱 내 [봉투 구매] 버튼을 통해 봉투만 별도로 구매하실 수 있습니다.\n\n\n[봉투 종류 및 가격 안내]\n\n- 80L 봉투: 300원 / 장\n- 150L 봉투: 1,000원 / 장\n(공통: 배송비 2,500원 별도)\n\n또한 신규 회원의 경우 최초 1회에 한해,\n배송비와 80L 봉투 1장 + 150L 봉투 1장이 무료로 제공됩니다.\n(탈퇴 및 수거 이력이 없는 경우에만 적용됩니다.)\n\n봉투 배송은 신청일 기준 약 3일 정도 소요됩니다.\n\n추가로 궁금하신 점이 있으시면 언제든지 문의 주세요.', '정책/수거이슈', 13),
('이용방법_무게초과', E'안녕하세요, 커버링 입니다.\n\n1봉투 당 15kg을 초과하는 경우에는 기사님 안전 및 봉투 터짐 등의 문제를 방지하기 위해 수거가 이루어지지 않을 수 있습니다.\n이 점 참고하여 수거 신청 부탁드립니다.', '정책/수거이슈', 14),
('이용방법_구독해지_환불불가', E'안녕하세요, 커버링 입니다.\n\n구독 해지하시면 다음 결제일에 결제가 진행되지 않으며, 이번 달 결제된 부분에 대해서는 환불이 진행되지 않습니다.\n\n참고로 고객님께서는 구독 혜택으로 주어지는 쿠폰을 사용하셨기 때문에 환불 진행이 어려운 점 양해 부탁드립니다.\n\n아울러, 구독 해지 희망하시는 사유를 기재해 주시면 해지 도와드리겠습니다.\n\n\n구독 해지 희망 사유 : \n\n\n** 남겨주신 사유는 팀 내에 공유하여 개선할 수 있도록 하겠습니다. 감사합니다', '정책/수거이슈', 15),
('이용방법_구독해지_환불O', E'안녕하세요, 커버링 입니다.\n\n구독 해지하시면 다음 결제일에 결제가 진행되지 않으며, 이번 달 결제된 부분에 대해서는 환불이 진행되지 않습니다.\n\n다만 고객님께서는 구독 환불 가능한 상태로 확인되어, 구독 해지 희망하시는 사유를 기재해 주시면 해지 및 환불 도와드리겠습니다.\n\n\n구독 해지 희망 사유 : \n\n\n** 남겨주신 사유는 팀 내에 공유하여 개선할 수 있도록 하겠습니다. 감사합니다.', '정책/수거이슈', 16);
INSERT INTO macros (name, content, category, sort_order) VALUES
('대량수거신청', E'대량 수거 희망하실 경우, 아래와 같이 진행 부탁드립니다.\n\n1. 앱 > 수거 신청 > 봉투10개로 수량 선택\n2. 배출하실 품목들 모두 봉투에 담기 ( + 상자에 담긴 경우, 노끈 등으로 손잡이 만들기 )\n3. 배출하실 품목 (봉투, 상자) 촬영하기\n4. 현재 채팅방으로 돌아와서 3번에서 촬영한 이미지 첨부 + 배출 수량은 몇 개 인지 전달하기', '수거방법/배출/요금', 1),
('대형봉투_수거신청', E'안녕하세요, 커버링 입니다.\n\n기존 수거는 봉투에 들어가는 사이즈만 수거가 가능했으나, 최근 대형 폐기물도 수거 가능한 서비스가 런칭 되었습니다!\n\n문의주신 품목은 저희 측에서 제공하는 150L 봉투를 통해 수거 가능한 형태로 보여지며,\n수거 희망하신다면 150L 봉투를 받아보신 후 해당 봉투에 품목을 담아 수거 신청 부탁드립니다.\n\n*대형 봉투 신청 방법 : 앱 > 봉투 구매 > 대형 폐기물 봉투 (150L) 선택\n\n단, 해당 봉투에서는 25kg 초과 시 수거 진행이 어려우며\n커버링 150L 봉투가 아닌 다른 봉투를 사용하실 경우에는 수거가 어려우니, 주의 부탁드립니다.\n\n** 요금은 일반 수거와 동일하게 \n기본 요금 2,500원 ( 배송비와 같은 개념 ) + 무게 140원/100g ( 선별 비용 ) 으로 무게 측정 후 청구될 예정입니다!', '수거방법/배출/요금', 2),
('대형봉투_크기', E'해당 봉투는 150L 사이즈로 제공되며,\n신장 155~ 160cm 기준과 사무용 의자로 비교했을 때 이 정도 됩니다!', '수거방법/배출/요금', 3),
('무게측정방법', E'안녕하세요, 커버링 입니다.\n봉투 당 15KG 가 초과할 경우는 정책 미준수로 수거 진행되지 않습니다.\n\n가정에서 가장 쉽게 무게를 예상할 수 있는 방법으로는,\n{봉투를 들고 측정한 고객님 체중 - 고객님 기본 체중 = 봉투 무게} 로 확인해 보실 수 있습니다!\n\n만일 체중계가 따로 구비되어 있지 않을 경우,\n한손으로 들었을 때 무겁게 느껴지신다면 여러 봉투에 나누어 담아주실 것을 권장드립니다.\n\n감사합니다.', '수거방법/배출/요금', 4),
('무게사진문의', E'안녕하세요, 커버링 입니다.\n\n저희는 과금이 진행되는 무게가 얼마인지를 중점으로 확인이 필요하기 때문에 '' 측정된 무게 '' 가 잘 보이도록 찍어 달라고 가이드 되고 있습니다.\n배출 품목과 함께 보이게 찍을 경우, 저울 빛 반사 & 배출 품목 사이즈 등으로 인해 무게 숫자 확인이 어려울 경우가 많을 수 있기 때문입니다.\n무게 측정에 있어서 배출된 품목만 측정 될 수 있도록 정직하게 측정 진행되고 있으니, 안심하고 사용해주시면 좋을 것 같습니다!\n\n아울러 품목 무게는 저울마다 미세한 차이가 있을 수는 있지만,\n가정에서 측정하는 것과 크게 다르지 않다는 점 참고 부탁드립니다.\n\n감사합니다 : )', '수거방법/배출/요금', 5),
('80L_배출정책안내', E'안녕하세요, 커버링 입니다.\n\n아래 사항을 따라 배출해 주셔야 원활한 수거가 가능합니다.\n\n1) 커버링 봉투 \n2) "커버링 수거" 메모가 작성/부착된 일반 봉투 \n3) 내용물이 담기지 않고, 전부 펼쳐진 종이 박스\n4) 봉투 당 15kg 미만으로 배출\n5) 찢어질 위험이 있거나 액체 흐름이 발생하지 않는 봉투\n6) 모든 봉투 포함 100kg 까지 배출\n7) 봉투의 입구를 묶어서 배출\n\n자세한 내용은 앱 내 이용방법에서 확인 가능하니 참고 부탁드립니다 :)', '수거방법/배출/요금', 6),
('대형_배출정책안내', E'안녕하세요, 커버링 입니다.\n\n150L 대형 폐기물 수거로 신청 주신 경우에는\n반드시 커버링에서 제공한 150L 봉투에 담겨 배출된 건에 한해 수거가 진행됩니다.\n\n따라서 아래와 같은 경우에는 수거 오인 및 안전 문제로 인해 수거가 어렵습니다.\n\n- 150L 봉투 대상 품목이나, 봉투에 담기지 않고 배출된 경우\n- 150L 봉투가 아닌 다른 봉투 또는 개별 물품 상태로 배출된 경우\n- 대형 물품이 외부에 그대로 노출되어 다른 물품과 혼동될 우려가 있는 경우\n- 25kg 초과하는 경우\n\n위와 같은 상황에서는 수거가 진행되지 않으니,\n번거로우시더라도 커버링 150L 봉투에 담아 밀봉 후 배출해 주시기 바랍니다.\n\n정확하고 안전한 수거를 위한 기준이오니 양해 부탁드립니다.\n감사합니다.', '수거방법/배출/요금', 7),
('봉투별배출정책', E'안녕하세요, 커버링 입니다.\n\n봉투 크기에 따라 수거 가능한 무게 정책이 달라서 아래 내용 확인하신 후 \n적합한 봉투를 신청하여 이용해 주시면 감사드리겠습니다!\n\n\n- 80L 봉투: 1봉투당 15kg 미만으로 배출\n- 150L 봉투: 1봉투당 25kg 미만으로 배출\n\n\n또한 150L 대형 봉투를 사용하신 후 ''일반 봉투 수거''로 신청하시는 경우에는,\n80L 봉투 정책과 동일하게 적용됩니다.\n\n안전한 수거를 위한 기준이오니 이용에 참고 부탁드립니다.', '수거방법/배출/요금', 8),
('다른봉투사용', E'다른 봉투 사용 후 ''커버링 수거'' 메모 부착해 배출해 주셔도 수거 가능하십니다 :)\n\n단,\n1. 손잡이 있는 봉투에 담아주시고\n2. 너무 얇아 찢어질 위험이 있거나, 물 흐름이 존재하는 경우는 수거가 어렵습니다.\n\n이 점 참고하여 이용 부탁드리겠습니다.', '수거방법/배출/요금', 9),
('배출품목_PP박스', E'안녕하세요, 커버링 입니다.\n\npp박스의 경우 내용물 없이 전부 펼친 상태에서 노끈으로 묶어 배출주시고, \n주문코드와 배출 사진을 해당 채널에 전달 주시면 원활히 수거 가능합니다 :)', '수거방법/배출/요금', 10),
('배출품목_날카로움', E'안녕하세요, 커버링 입니다.\n\n유리나 칼 등 깨질 우려가 있거나 날카로운 품목의 경우, 신문지나 작은 박스/쇼핑백 등으로 한 번 더 밀봉하여 봉투 안에 넣어주시면 감사하겠습니다 :)', '수거방법/배출/요금', 11),
('배출품목_종이박스', E'안녕하세요, 커버링 입니다.\n\n박스는 아래 이미지와 같이 전부 펼쳐서 배출해 주셔야 원활히 수거 가능합니다.\n펼치기 애매한 사이즈의 박스나 쇼핑백 등은 커버링 봉투 안에 넣어주시면 감사하겠습니다 :)', '수거방법/배출/요금', 12),
('배출품목_의약품', E'안녕하세요, 커버링 입니다.\n\n커버링 봉투에 들어가는 대부분의 생활 폐기물은 수거 가능하지만,\n의약품은 법적으로 일반 쓰레기로 버리면 안 되는 ''특수 폐기물'' 이기 때문에 저희측에서 수거가 어렵습니다.\n\n따라서 의약품은 수거가 어려우며, 혹시라도 실수로 배출하신 경우에는 저희 측에서 적법한 방법으로 자체 폐기 진행하고 있습니다만-\n의약품 외에도 [화재 위험 품목, 산업 폐기물] 은 수거가 어렵다는 점 참고 부탁드립니다.\n\n감사합니다 : )', '수거방법/배출/요금', 13),
('외부배출', E'안녕하세요, 커버링입니다.\n\n외부에 배출하실 경우, 요청사항에 위치를 상세히 기재하고 배출 위치 사진을 업로드해 주시면 보다 원활하게 수거가 가능합니다.\n다만 외부 배출 특성상 쓰레기 분실이나 환경미화원에 의한 수거가 발생할 수 있으니, 이 점 꼭 참고 부탁드립니다.\n\n조금 번거로우시겠지만, 보다 안전하고 확실한 수거를 위해 안내드린 방법으로 진행 부탁드립니다. \n감사합니다.', '수거방법/배출/요금', 14),
('이용요금', E'서비스 이용 요금은 배출 무게에 따라 상이하며,\n수거 1건 당 기본요금 2,500원 ( 배송비와 같은 개념 ) + 무게 140원/100g ( 선별 비용 ) 으로 무게 측정 후 청구됩니다.', '수거방법/배출/요금', 15),
('지역오픈', E'안녕하세요, 커버링입니다.\n저희 서비스를 관심 가지고 이용하고 싶다고 말씀해 주셔서 정말 감사드립니다!\n\n커버링은 꾸준히 서비스 지역을 확장하고 있으며, 현재 서비스 어려운 지역도 빠르게 이용하실 수 있도록 준비 중입니다.\n\n또한, 고객님께서 받아보신 쿠폰이 만료되더라도 해당 지역 서비스가 오픈되면 재발급해 드릴 예정입니다.\n만일 재발급이 확인되지 않는 경우에는 지금처럼 편하게 문의 주시면 바로 도와드리겠습니다.\n\n조금만 더 기다려 주시면 좋은 소식 전해드릴 수 있을 것 같습니다.\n기대해 주셔서 다시 한 번 감사드리며, 더 가까운 곳에서 만날 날을 기다리고 있겠습니다!', '수거방법/배출/요금', 16);
INSERT INTO macros (name, content, category, sort_order) VALUES
('봉투배송소요일', E'안녕하세요, 커버링 입니다. \n\n봉투 배송은 신청일로부터 최대 2일 정도 소요됩니다.\n\n감사합니다 :)', '봉투/배송/영수증', 1),
('봉투정상지급', E'안녕하세요, 커버링입니다.\n\n해당 내용 확인 시, 기사님이 해당 위치에 전달 드린 것으로 확인됩니다.\n혹시 고객님께서는 해당 위치에서 확인 어려우실까요?', '봉투/배송/영수증', 2),
('기본봉투미지급_유저과실', E'안녕하세요, 커버링입니다.\n\n문의 주신 주문건 확인해 본 결과, 수거신청 시 "수거 후 무료봉투 안주셔도 돼요" 를 선택하셔서 봉투가 지급되지 않은 것으로 확인됩니다.\n\n수거 후 기본 봉투 지급이 필요하신 경우, \n수거 신청 시 "수거 후 무료봉투 안주셔도 돼요" 를 선택 해제해 주셔야 정상적으로 지급됩니다.\n\n아울러, 이용 정책만 잘 지켜주신다면 \n다른 봉투 사용 후 ''커버링 수거'' 메모 부착해 배출해 주셔도 수거 가능한 점 참고 부탁드립니다.', '봉투/배송/영수증', 3),
('기본봉투분실', E'죄송하게도 분실 된 기본 봉투에 대해서는 다시 무료 배송이 어려운 점 양해 부탁드립니다.\n필요 시 기본요금과 장 당 봉투 비용 과금으로 구매 배송 진행 가능하며, \n꼭 커버링 봉투가 아니더라도 다른 봉투 사용 후 ''커버링 수거'' 메모 부착해 배출해주셔도 원활히 수거 가능합니다.\n\n혹시 괜찮으시다면 이번만 다른 봉투를 마련하여 수거 신청 주실 수 있으실까요?\n신청 주실 때 "수거 후 무료봉투 안주셔도 돼요" 에 체크하지 마시고 신청해 주시면 기본 봉투를 함께 발송드리겠습니다.', '봉투/배송/영수증', 4),
('영수증', E'안녕하세요, 커버링 입니다.\n\n최근 결제 서비스사(PG사) 변경으로 인해 이전처럼 영수증 발급을 별도로 제공해 드리기는 어려운 점 안내 드립니다.\n결제 영수증이 필요하신 경우, 이용하신 카드사 홈페이지·앱·고객센터를 통해 직접 확인 및 발급 받으실 수 있습니다.\n\n감사합니다 :)', '봉투/배송/영수증', 5),
('봉투배출요청', E'안녕하세요, 커버링 입니다.\n\n커버링 봉투가 없으시다면 앱 내에서 [봉투 구매] 를 통해 원하시는 수량만큼 구매하실 수 있습니다. (장 당 300원/ 배송비 2,500원)\n\n또는 별도로 큰 봉투를 마련하신 후 ''커버링 수거'' 가 기재된 메모를 부착하여 배출해 주셔도 됩니다.\n\n다만, 수거 기사님이 봉투에 직접 나눠 담아야 하는 경우에는 수거가 어렵습니다.\n바로 들 수 있고, 바로 무게 측정이 가능한 형태로 배출해 주셔야 정상적으로 수거가 진행된다는 점 참고하여 이용 부탁드립니다.', '봉투/배송/영수증', 6),
('첫이용봉투안내', E'안녕하세요, 커버링 입니다.\n\n커버링은 이용 내역 없는 계정에 한하여, \n커버링 봉투 1장을 무료 배송으로 신청하실 수 있습니다.\n( 필요하시다면 1회 주문에서 더 많은 수량의 봉투를 추가로 구매하실 수도 있습니다. )\n\n*커버링 앱 > [봉투 구매] 버튼 클릭 > 원하시는 구매 수량 선택\n\n이용 내역이 존재하는 경우에는 1장 무료 지급 + 무료 배송이 어려운 점 양해 부탁 드립니다.\n\n** 참고로 꼭 커버링 봉투가 아니더라도 \n다른 봉투 사용 > ''커버링 수거'' 메모 부착하여 배출해 주셔도 수거 가능합니다.', '봉투/배송/영수증', 7),
('봉투안내', E'봉투는 배출 품목만 전부 담긴다면, 아무 봉투나 사용하셔도 됩니다.\n단, 터질 위험이 있는 봉투는 수거가 어렵습니다 :(\n\n편의점 봉투, 종량제 봉투, 쇼핑백 등 모두 사용 가능하시며, 배출 품목을 담고 잘 묶어서 \n"커버링 수거" 라는 문구를 기재해 부착해 주시면 됩니다.\n해당 봉투는 희망하시는 위치에 배출 후, 저희측으로 위치를 정확히 기재하여 신청 주시기 바랍니다.', '봉투/배송/영수증', 8),
('봉투만구매_미수거안내', E'안녕하세요, 커버링 입니다.\n\n이번에 신청하신 건은 수거 신청건이 아닌, 봉투만 받아보실 수 있는 "봉투 구매" 주문건으로 확인됩니다.\n\n해당 주문에서는 수거 진행은 이루어지지 않으며,\n저희 서비스를 이용하실 수 있는 봉투만 선택하신 수량만큼 발송됩니다.\n\n이용에 참고 부탁 드립니다.\n감사합니다 :)', '봉투/배송/영수증', 9),
('서비스봉투문의', E'기존에는 봉투만 구매할 수 있는 기능이 제공되지 않아서 수거 없이 봉투만 구매 희망 시,\n앱에서 수거 신청 후 저희 측에 별도로 신청 문의를 주셔야만 했습니다.\n\n이러한 번거로움에 죄송함과 감사함을 담아, 1장 서비스 봉투로 지급 드렸었는데요-\n\n이제는 앱 내에서 직접 수거 없이 봉투만 구매하실 수 있도록 기능이 제공되어, 구매하신 수량만큼 발송되는 점 양해 부탁드립니다.\n\n단, 수거 신청 시에는 기존처럼 기본 봉투 1장이 무료로 제공됩니다 :)', '봉투/배송/영수증', 10);
INSERT INTO macros (name, content, category, sort_order) VALUES
('계좌이체', E'안녕하세요, 커버링입니다.\n\n현재 커버링은 카드 또는 카카오페이 간편결제만 지원되고 있으나, 이번 건은 예외적으로 계좌이체로 도와드리겠습니다.\n\n기업은행 039-079846-04-073\n(주)커버링\n\n위 계좌로 이체하신 후, 아래 정보를 함께 전달해 주시면 확인 후 처리 도와드리겠습니다.\n\n1. 수거 내역 스크린샷\n2. 이체 내역 스크린샷\n3. 예금자 명\n\n감사합니다.', '결제/앱/일반', 1),
('카카오페이머니중복결제', E'안녕하세요, 커버링 입니다.\n\n문의주신 내용으로 확인해본 결과, 고객님께서 직접 결제하시는 단계에서 카카오페이 결제를 선택해 주신 것으로 확인됩니다.\n \n카카오페이 결제는 통장에서 카카오페이머니로 먼저 금액 충전이 되고, 충전된 머니에서 커버링으로 결제되는 방식입니다.\n즉, 1차로 카카오페이머니 충전을 위해 결제가 된 후, 2차로 해당 머니 통장에서 커버링으로 다시 결제가 이루어지는 형태로 이해해 주시면 됩니다!\n\n결과적으로 해당 건은 현재 {입금 대기 / 결제완료 상황에 맞게 사용} 상태로 확인되는 점 참고 부탁드리며, 고객님께서도 한번 더 결제 내역을 확인해 주시기 바랍니다.\n\n감사합니다.', '결제/앱/일반', 2),
('다른결제수단', E'안녕하세요, 커버링입니다.\n\n현재는 카드 결제와 카카오페이 간편결제만 이용 가능하여, 계좌이체 등 다른 결제수단은 지원되지 않습니다.\n이용에 불편을 드려 죄송합니다.\n\n미결제된 건은 매일 오후 3시, 등록된 카드로 자동 결제가 진행됩니다.\n만약 자동 결제가 어려운 경우에는, 앱 내 [이용 내역] 탭에서 해당 수거 건의 상세 페이지로 들어가 직접 결제도 가능합니다.\n\n감사합니다.', '결제/앱/일반', 3),
('수거시간지정', E'안녕하세요, 커버링 입니다.\n\n현재 수거의 경우, 밤 10시 이후부터 순차적으로 진행되고 있습니다.\n기사님이 방문하는 동선이 매번 달라 특정 시간을 지정하여 수거 요청은 불가능한 점 양해 부탁드립니다.', '결제/앱/일반', 4),
('수거시간확인요청', E'안녕하세요, 커버링입니다.\n\n현재 커버링의 수거는 밤 10시 이후부터 순차적으로 진행되고 있습니다.\n이로 인해 고객님께서 직접 수거 시간을 지정하실 수 없는 점 양해 부탁드립니다.\n\n또한 아직은 정확한 수거 예상 시간 안내 기능이 제공되지 않지만,\n더 편리하게 이용하실 수 있도록 현재 해당 기능을 개발 중에 있습니다.\n\n업데이트가 완료되는 대로 앱 내 공지를 통해 안내 드리겠습니다.\n\n감사합니다.', '결제/앱/일반', 5),
('수거가능요일', E'안녕하세요, 커버링입니다.\n\n지역별로 수거 가능 요일이 다르기 때문에 \n앱 내 [내 정보 > 서비스 지역] 페이지에서 확인해 주시면 됩니다.\n\n\n또한, 수거 신청 시 날짜 선택이 가능하다면 해당 날짜에 정상적으로 수거가 진행되니 참고 부탁드립니다.\n\n감사합니다.', '결제/앱/일반', 6),
('자동결제', E'안녕하세요, 커버링 입니다.\n\n결제는 수거일 익일 오후 3시에 자동으로 진행됩니다.\n또한, 앱 내 이용내역 탭에서 해당 수거 건의 상세 페이지로 들어가 직접 결제하실 수도 있습니다.\n\n감사합니다.', '결제/앱/일반', 7),
('결제취소', E'안녕하세요, 커버링 입니다.\n\n아쉽지만 현재 시스템상 결제 완료 후 쿠폰 적용을 위해 취소 및 재결제를 진행하는 기능은 지원되지 않습니다.\n쿠폰은 반드시 결제 전에 적용해 주셔야 정상 반영되오니 이 점 참고 부탁드립니다.\n\n더 편리하게 이용하실 수 있도록 해당 기능도 내부적으로 검토 중이니, 조금만 너그럽게 기다려주시면 감사하겠습니다.', '결제/앱/일반', 8),
('주소검색', E'안녕하세요, 커버링 입니다.\n\n도로명 주소 전체를 입력해주셔야 주소 검색이 원활하게 이루어집니다. (ex. 새문안로5길 13)\n위와 같이 재시도 해보시기 바라며, 글자 간 공백(띄어쓰기) 까지 정확하게 입력해 주셔야 하는 점 참고 부탁드립니다.\n\n감사합니다.', '결제/앱/일반', 9),
('한글입력안됨', E'안녕하세요, 커버링 입니다.\n\n혹시 기기에서 제공하는 기본 키보드가 아닌 다른 키보드 사용 중이실까요?\n커스텀 키보드를 이용하실 경우에는 한글 입력이 안되거나 가능한 특수문자 입력이 안되는 등 원활하게 작동하지 않을 수 있습니다.\n사용하시는 기기 설정 > 키보드 설정에서 "기본 키보드" 로 변경 후 다시 시도해 보시기 바랍니다.', '결제/앱/일반', 10),
('분실물찾기', E'안녕하세요, 커버링 입니다.\n\n문의주신 분실물에 대해 내부 공지 후 확인해 보았으나, 분실물 처리된 물품이 없었던 것으로 확인됩니다.\n소중한 물건을 분실하게 되어 많이 속상하실 것 같아 최대한 찾아드리고 싶었으나, 도움 드리지 못해 죄송합니다.\n\n커버링의 선별장에는 하루에 몇천 건 이상의 쓰레기 봉투들이 들어오고 있습니다.\n이러한 더미 속에서 분실물을 찾아드리기가 매우 어려운 부분에 대해 양해 부탁드립니다.\n\n감사합니다.', '결제/앱/일반', 11),
('처리방법', E'안녕하세요, 커버링 입니다.\n\n실제로 커버링이 수거한 쓰레기들이 어떻게  처리가 되고 있는지 궁금하신 듯 합니다!\n저희는 수거한 쓰레기를 순환 가능한 자원으로 재활용 하고 있습니다 :)\n\n참고로 수거 된 쓰레기는 선별장으로 이동하여 종류 별로 분리수거 과정을 거치고 있습니다.\n이 과정에서 종류에 따라 각 업체로 보내져 재활용 및 폐기 처리가 된답니다 :)\n\n아울러, 앞으로도 고객님께서 우려 없이 이용하실 수 있도록\n커버링 선별장으로 이동 된 쓰레기가 처리되는 과정을 담은 내용도 보다 투명하게 보여드릴 수 있도록 고민하겠으며, 친환경적인 서비스 제공을 위해 힘쓰겠습니다.', '결제/앱/일반', 12),
('페이백', E'안녕하세요, 커버링 입니다.\n\n커버링은 옷을 수거하고 페이백 드리는 서비스가 아닌, 분리수거 없이 한 봉투 안에 생활 폐기물을 담아주시면 수거해 드리는 서비스를 제공하고 있어요.\n혹시라도 페이백 서비스를 기대하셨다면 해당 서비스를 제공 드리지 못해 죄송합니다.\n추후에는 말씀 주신 부분까지 만족 시켜드릴 수 있는 방안을 고민해 보겠습니다.\n\n감사합니다.', '결제/앱/일반', 13);
INSERT INTO macros (name, content, category, sort_order) VALUES
('B2B_도입', E'안녕하세요, 커버링 입니다.\n\n해당 문의는 아래 채널을 통해 문의 주세요!\n\nB2B 도입 문의하러 가기! (클릭)\n\n*해당 채널에서 문의 남겨주시면 담당자 확인 후 안내 드릴게요 :)', 'B2B/채널안내/오피스', 1),
('채널안내_방문수거', E'안녕하세요, 커버링 입니다.\n\n문의 주신 내용은 ''커버링 방문 수거'' 서비스를 통해 진행이 가능할 것으로 보여져 관련하여 문의하실 수 있는 창구를 안내 드립니다!\n\n아래 버튼 클릭하신 후 견적 요청 주시면 담당 부서에서 확인 후 순차적으로 안내 드리고 있습니다.\n\n번거로우시겠지만, 해당 창구를 통해 견적 요청 접수 부탁드립니다', 'B2B/채널안내/오피스', 2),
('채널안내_런치', E'안녕하세요, 커버링 입니다.\n\n커버링 런치 수거 관련 문의는 아래 채널을 통해 문의 부탁드립니다 :)\n\n커버링 런치 문의하러 가기! (클릭)', 'B2B/채널안내/오피스', 3),
('채널안내_오피스', E'안녕하세요, 커버링 입니다.\n\n커버링 오피스 수거 서비스와 관련한 문의는 아래 채널을 통해 문의 주세요!\n\n커버링 오피스 수거 신청하러 가기 (클릭)\n\n*해당 채널에서 문의 남겨주시면 담당자 확인 후 안내 드릴게요 :)', 'B2B/채널안내/오피스', 4),
('오피스_무료체험', E'커버링 오피스 무료체험 신청\n\n아래 신청 양식대로 내용 남겨주시면, \n매니저가 확인 후 연락드릴 예정입니다 :) \n\n\n1. 무료체험 시작일 ( 키트 당일 야간 배송 가능 )  \n2. 수거 요일 ( ex. 매주 월, 금 )   \n3. 수거 주소 및 새벽 출입방법  \n4. 필요한 키트 수 ( 월 수거 된 키트 개수 * 키트 금액 정산 )\n5. 회사명 / 담당자명 / 담당자 연락처 / 담당자 이메일  \n6. 정산 방법 ( 계좌이체, 법인카드 결제 )  \n\n\n관련하여 궁금하신 내용이 있으실 경우,\n말씀해 주시면 안내 드리겠습니다.', 'B2B/채널안내/오피스', 5),
('오피스_전환여부', E'안녕하세요, 커버링 오피스 입니다  \n\n이용해 주신 2주 무료 체험 서비스가 곧 종료됩니다!\n\n앞으로도 분리 배출 걱정 없이 쾌적한 사무 공간을 유지하시려면 정기 구독 전환이 필요합니다. \n\n계속 이용을 원하신다면 "예" , 이용을 종료하시려면 "아니오" 라고 회신 주시면 됩니다.\n\n\n고객님의 선택을 기다리겠습니다:) \n\n감사합니다.', 'B2B/채널안내/오피스', 6),
('오피스_첫수거', E'안녕하세요, 커버링 오피스입니다 \n\n오늘 첫 수거는 불편 없이 잘 진행되셨을까요?  \n\n혹시라도 아쉬운 점이나 개선이 필요한 부분이 있다면 언제든 알려주세요!\n\n고객님의 작은 목소리도 놓치지 않고 더 나은 서비스로 보답하겠습니다\n\n앞으로도 쓰레기 걱정 없는 쾌적한 공간을 위해 꼼꼼히 챙기겠습니다.\n\n감사합니다 :)', 'B2B/채널안내/오피스', 7),
('오피스_키트발송', E'안녕하세요, 커버링 오피스입니다 \n\n보내드린 오피스 키트 ( 120L 전용 통·안내 종이·개인 고객 쿠폰 ) 는 잘 받아보셨나요?  \n\n이제는 분리 배출 걱정 없이, 쓰레기를 전용 통에 담아주시면 됩니다!\n나머지는 저희가 꼼꼼히 챙기겠습니다. \n\n안내 종이는 꼭 붙이지 않으셔도 되지만,\n부착해 두시면 구성원 분들이 서비스를 더 편리하게 이용하실 수 있어요 :)\n\n함께 드린 개인 고객 무료 쿠폰은 커버링 앱에서 사용 가능하며,\n구성원 분들이 가정에서도 커버링을 경험해 보실 수 있습니다.\n\n늘 쾌적한 공간을 위해 세심히 함께하겠습니다.  \n감사합니다 :)  \n\n커버링 드림', 'B2B/채널안내/오피스', 8),
('스파크플러스코엑스_수거안내', E'안녕하세요, 커버링 입니다.\n\n스파크플러스 코엑스점 수거는 매월 마지막주 금요일 야간 (9월 27일) 에 수거가 진행되고 있습니다.\n\n아래 내용 작성 부탁드립니다.\n\n기업명 :\n담당자 : 이름 & 연락처 & 이메일\n배출 품목 :\n\n운영사무실에서 제공하는 커버링 봉투가 아닌 경우, 수거 대상 품목에 "커버링 수거" 메모를 남겨주셔야 정상적으로 수거가 가능하며, \n배출해주신 후 배출 사진 첨부해주시면 감사하겠습니다.\n\n정산은 세금계산서 발행 후 계좌이체의 형태로 진행되며, 수거 완료 후 작성주신 연락처 및 이메일로 정산 요청드릴 예정입니다 :)', 'B2B/채널안내/오피스', 9),
('제휴문의', E'안녕하세요, 커버링 입니다.\n\n제휴 관련 내용은 support@covering.app 으로 메일 전달 주시면 담당자 확인 후 회신 드릴 수 있도록 하겠습니다.\n\n감사합니다 :)', 'B2B/채널안내/오피스', 10);
INSERT INTO macros (name, content, category, sort_order) VALUES
('차량등록과정', E'안녕하세요, 커버링 입니다.\n\n차량 등록 요청을 주시면 아래 과정으로 진행됩니다.\n\n1 ) 고객님 > 앱 내에서 수거 신청\n2 ) 수거 당일 오후 10시 전까지 채널톡 문의 > " 금일 수거 입니다, 차량 등록을 위해 차량 번호를 알려주세요. "\n3 ) 커버링 > 방문 차량 확인 후, 고객님께 차량 번호 전달', '차량/배차', 1),
('차량번호', E'안녕하세요, 커버링 입니다.\n\n방문 드리는 차량의 경우, \n밤 9시 이후 배차가 진행된 후 확인이 가능하여\n배차 완료된 후에 해당 채팅을 통해 차량 번호 전달 드릴 수 있도록 하겠습니다.', '차량/배차', 2),
('차량번호_2', E'안녕하세요, 커버링 입니다.\n\n아직 배차가 진행되기 전으로 확인됩니다.\n배차 진행 후 해당 채팅방을 통해 전달드리겠습니다!', '차량/배차', 3),
('차량안내', E'고객님, 기다려주셔서 감사합니다. \n \nOO\n\n차량 방문 예정으로 전달 드립니다!', '차량/배차', 4),
('차량등록_고객접수취소', E'안녕하세요, 고객님\n좋은 아침입니다!\n\n전일 신청해주신 건 접수 취소로 확인되어 배차 안내를 드리지 못한 점 참고 부탁드립니다.\n추후 필요하실 때 다시 문의 주시면 차량 배차 후 안내 도와드릴 수 있도록 하겠습니다.\n\n감사합니다.\n오늘도 좋은 하루 되세요!', '차량/배차', 5);
INSERT INTO macros (name, content, category, sort_order) VALUES
('보상_쿠폰발급', E'아울러 죄송한 마음을 담아 할인 쿠폰 발급하여 드렸습니다.\n괜찮으시다면 해당 쿠폰을 통해 다시 한번 수거 서비스를 이용 부탁드립니다.\n\n추가로 기존 주문에 등록하신 쿠폰이 있으신 경우에는 앱 내 이용내역 > 주문상세에서 직접 등록한 쿠폰의 등록 취소도 가능하니,\n이용에 참고 부탁드립니다.', '보상/환불', 1),
('보상_기사님실수', E'기다려 주셔서 감사합니다.\n말씀주신 내용에 대해 기사님 피드백 완료하였으며, 추후 동일 문제가 발생하지 않도록 더욱 신경쓰겠습니다.\n\n기 접수건은 저희측에서 취소처리 하여 추후 수거 재신청 하실 수 있도록 하였습니다.\n아울러 죄송한 마음을 담아 할인 쿠폰 발급하여 드렸습니다.\n괜찮으시다면 해당 쿠폰을 사용해 다시 한번 수거 서비스를 이용해 주시면 감사드리겠습니다.', '보상/환불', 2),
('보상_구매봉투미지급', E'안녕하세요, 커버링입니다.\n\n먼저 서비스 이용에 불편을 드려 진심으로 죄송합니다.\n확인 결과, 기사님께서 착오로 봉투를 적게 지급하신 것으로 확인되었습니다.\n\n초과 결제된 금액은 취소 처리해드리겠습니다.\n추후에 신청해 주셨을 때는 문제 없이 지급될 수 있도록 하겠습니다.\n\n더 나은 서비스 제공을 위해 계속 노력하겠습니다.\n감사합니다.', '보상/환불', 3),
('보상_구매봉투누락', E'안녕하세요, 커버링입니다.\n\n먼저 이용에 불편을 드리게 되어 죄송합니다.\n\n문의 주신 내용을 확인해보니, 해당 건은 기사님 착오로 인해 봉투가 1장만 지급 된 것으로 보입니다.\n\n구매하신 봉투는 담당 부서에 재 발송 요청 하였으며,\n받아보시기 까지 최대 2일 까지 소요되는 점 참고 부탁드립니다.\n\n** 참고로 커버링 지급 봉투가 아닌 다른 봉투에 배출 품목을 담아 ''커버링 수거'' 메모 부착하여 배출해 주셔도 원활히 수거 가능합니다.\n\n혹시 급하게 수거가 필요하시다면, 해당 형태로 배출 후 수거 신청 부탁드립니다.\n\n추후에 구매해 주셨을 때는 문제 없이 지급될 수 있도록 하겠습니다.\n\n더 나은 서비스 제공을 위해 계속 노력하겠습니다.\n감사합니다.', '보상/환불', 4),
('보상_오인수거_보상제안', E'고객님, 기다려 주셔서 감사합니다.\n\n저희 내부에서 논의한 결과에 대해 안내 드리기에 앞서,\n믿고 이용해 주셨는데  오인수거 건으로 불편을 드린 점 다시 한 번 진심으로 사과드립니다.\n\n고객님께서 제출해주신 증빙 자료 및 내부 확인 결과를 바탕으로, 아래와 같이 보상 진행 드리고자 합니다.\n\n\n- 총 피해 물품 가액(증빙 기준) : \n- 보상 산정 기준 : 증빙 확인된 품목을 기준으로 산정하였으며, 확인 가능한 범위 내에서 내부 보상 기준을 적용하였습니다.\n- 최종 현금 보상금액 : \n- 추가 보상 : 차기 이용 시 사용 가능한 10% 할인 쿠폰 지급\n\n\n위 내용으로 보상 절차를 진행 드리고자 하며,\n안내드린 내용 확인 후 이상 없으시다면 진행 도와드리겠습니다.', '보상/환불', 5),
('보상_오인수거_증빙양식', E'이용 중 불편을 겪으시게 되어 진심으로 죄송합니다.\n소중한 물품이 잘못 수거된 점 깊이 사과드리며, 정확한 보상 절차를 위해 아래 양식 작성 부탁드립니다.\n\n- 오인수거 된 물품 : \n- 봉투에 담겨 있던 물품의 브랜드 및 가액 : \n\n*가능하시다면 구매 내역(영수증, 주문 내역 캡처 등)을 함께 첨부해 주세요.\n\n확인 후 내부 절차에 따라 보상 검토를 신속히 진행하겠습니다.\n다시 한번 불편을 드려 죄송합니다.', '보상/환불', 6),
('보상_기사님주소혼동_결제O', E'기다려 주셔서 감사합니다.\n\n확인해본 결과, 기사님께서 착오로 다른 주소지를 방문하신 것으로 보입니다.\n\n이용에 불편을 드려 진심으로 죄송스럽습니다.\n해당 기사님께 피드백을 완료하였으며, 추후 동일 문제가 발생하지 않도록 더욱 신경 쓰겠습니다.\n\n기 접수건은 저희 측에서 취소 처리하였으며, 이미 결제 완료된 금액은 1~ 3영업일 이내 결제하신 수단을 통해 환불 될 예정이니 참고 부탁드립니다.\n\n아울러 죄송한 마음을 담아 할인 쿠폰도 발급해 드렸습니다.\n괜찮으시다면 해당 쿠폰을 사용해 다시 한번 수거 서비스를 이용해 주시면 감사드리겠습니다.', '보상/환불', 7),
('보상_기사님주소혼동_결제X', E'기다려 주셔서 감사합니다.\n\n확인해본 결과, 기사님께서 착오로 다른 주소지를 방문하신 것으로 보입니다.\n\n이용에 불편을 드려 진심으로 죄송스럽습니다.\n해당 기사님께 피드백을 완료하였으며, 추후 동일 문제가 발생하지 않도록 더욱 신경쓰겠습니다.\n\n기 접수건은 저희 측에서 취소하여 수거 재신청 하실 수 있도록 처리하였으며,\n아울러 죄송한 마음을 담아 할인 쿠폰도 발급해 드렸습니다.\n\n괜찮으시다면 해당 쿠폰을 사용해 다시 한번 수거 서비스를 이용해 주시면 감사드리겠습니다.', '보상/환불', 8),
('보상_다른집물품수거', E'서비스 이용에 불편을 드려 죄송합니다.\n야간에 수거가 이루어지다 보니, 기사님께서 오인하여 수거를 진행하신 듯 보입니다.\n이로 인해 과도한 금액을 받아보시고 많이 당황스러우셨을 것 같아 마음이 매우 무겁습니다.\n\n먼저 해당 수거 주문건에 대해서는 전액 결제가 되지 않도록 조치하였으며, 죄송스러운 마음을 담아 쿠폰을 지급해 드렸습니다.\n괜찮으시다면 추후 필요하실 때 해당 쿠폰을 이용해 저희 서비스를 다시 이용을 부탁드립니다.\n다시 신청 주셨을 때는 수거가 문제없이 진행될 수 있도록 보다 신경쓰겠습니다.\n\n마지막으로, 해당 기사님께는 해당 내용을 전달하여 동일한 문제가 반복되지 않도록 개선하겠습니다.\n\n감사합니다.', '보상/환불', 9),
('보상_수거누락_재수거', E'안녕하세요, 커버링 입니다.\n\n서비스 이용에 불편을 드려 죄송합니다.\n야간에 수거가 이루어지다 보니, 기사님께서 일부 수거 건 누락하신 듯 합니다.\n이로 인해 고객님께서 많이 난처하셨을 것 같아 마음이 매우 무겁습니다.\n\n번거로우시겠지만, 혹시 누락된 수거품의 이미지를 첨부해 주실 수 있으실까요?\n\n아울러 죄송한 마음을 담아 할인 쿠폰 발급하여 드렸습니다.\n괜찮으시다면 해당 쿠폰을 통해 다시 한번 수거 서비스를 이용 부탁드립니다.', '보상/환불', 10),
('보상_수거누락', E'안녕하세요, 커버링 입니다.\n\n서비스 이용에 불편을 드려 죄송합니다.\n야간에 수거가 이루어지다 보니, 기사님께서 일부 수거 건 누락하신 듯 합니다.\n이로 인해 고객님께서 많이 난처하셨을 것 같아 마음이 매우 무겁습니다.\n\n매우 번거로우시겠지만, 이번 건에 대해 수거 재신청 해주실 수 있으실까요?\n아울러 죄송한 마음을 담아 할인 쿠폰 발급하여 드렸습니다.\n괜찮으시다면 해당 쿠폰을 통해 다시 한번 수거 서비스를 이용 부탁드립니다.', '보상/환불', 11),
('보상_수거지연강성', E'안녕하세요, 커버링 입니다.\n\n최근 수거량이 급증하면서 일부 지역에서 수거가 지연되는 경우가 발생하고 있습니다.\n이번 지연으로 서비스 이용에 불편을 드려 정말 죄송합니다.\n\n해당 건은 현재 수거가 완료되었음을 안내 드립니다.\n아울러, 불편을 끼쳐드린 점에 대한 사과의 마음으로 할인 쿠폰을 발급해드렸습니다.\n\n같은 불편이 반복되지 않도록 내부 시스템을 개선하고,\n더 원활한 수거 서비스로 보답드리겠습니다.\n\n감사합니다.', '보상/환불', 12),
('보상_무게오입력_결제X', E'안녕하세요, 커버링입니다.\n\n먼저 이용에 불편을 드려 죄송합니다.\n\n확인 결과, 기사님께서 무게를 잘못 입력하신 것으로 확인되었습니다.\n해당 건 실제 측정 된 무게 기준으로 수정하여 과한 요금이 청구되지 않도록 조치 완료하였습니다.\n\n해당 기사님께는 동일한 문제가 재발하지 않도록 주의 요청 드렸으며,\n내부적으로도 무게 입력 절차를 점검해 개선될 수 있도록 하겠습니다.\n\n추가로, 불편을 드린 점에 대한 사과의 의미로 쿠폰을 함께 지급 드렸습니다.\n다시 한 번 이용에 불편을 드린 점 진심으로 사과드립니다.\n\n감사합니다.', '보상/환불', 13),
('보상_무게오입력_결제O', E'안녕하세요, 커버링입니다.\n\n먼저 이용에 불편을 드려 죄송합니다.\n\n확인 결과, 기사님께서 무게를 잘못 입력하신 것으로 확인되어 실제 무게 기준으로 금액을 재 산정 하였으며, \n과하게 결제된 금액은 부분 환불 처리되었습니다.\n확인하신 결제 내역은 카드사 사정에 따라 1~3영업일 내 정정 반영됩니다.\n\n해당 기사님께는 동일한 문제가 재발하지 않도록 주의 요청 드렸으며,\n내부적으로도 관련 절차를 점검해 개선될 수 있도록 하겠습니다.\n\n또한 불편을 겪으신 점에 대한 사과의 의미로 쿠폰을 함께 지급 드렸습니다.\n\n다시 한 번 이용에 불편을 드린 점 사과드립니다.\n감사합니다.', '보상/환불', 14),
('감사_무게덜입력', E'안녕하세요, 커버링 입니다.\n\n무게 오 입력으로 혼선을 드려 죄송합니다..!\n아울러, 무게가 적게 입력되었음에도 먼저 말씀해 주셔서 정말 감사드립니다\n\n원칙적으로는 봉투 무게에 따른 추가 과금이 되어야 하는 것이 맞으나, \n해당 건에 대해서는 추가 과금 없이 진행해 주시면 됩니다 :)\n\n추가로 감사한 마음을 담아 쿠폰 발급 드렸습니다!\n앞으로도 커버링 서비스 많이 이용 부탁드려요 :)', '보상/환불', 15),
('환불_구독', E'확인 감사드립니다!\n구독 혜택 쿠폰 (5,900원) 사용 시에는 환불 및 구독 해지가 어려운 점 참고 부탁드리며,\n환불 완료되었음을 안내드립니다.\n실제 환불은 카드사 정책에 따라 영업일 기준 3-5일 소요될 수 있으며,\n구독 해지는 금일 오후 6시 이후에 완료될 예정이오니 참고 부탁드립니다.\n\n감사합니다.', '보상/환불', 16),
('해지_구독', E'확인 감사드립니다!\n\n금일 오후 6시 이후에 구독 해지 처리될 예정입니다.\n이후 구독 상태 확인 부탁드리겠습니다.\n\n저희 서비스 이용 중 불편 생기실 경우에는 언제든지 편하게 문의 부탁드립니다 :)\n감사합니다.', '보상/환불', 17);
INSERT INTO macros (name, content, category, sort_order) VALUES
('빼기_커버링미숙지', E'안녕하세요, 커버링입니다.\n\n고객님께서는 ''빼기'' 앱 > "문 앞 수거 서비스" 를 통해 저희 커버링 수거 서비스를 이용해 주신 것으로 확인됩니다.\n\n이용하고 계신 ''빼기'' 는 대형 폐기물 처리, 중고 매입 등 다양한 생활 정리 서비스를 제공하는 플랫폼이며,\n저희 커버링은 ''빼기''와 제휴하여 실제 수거를 진행하는 전문 업체입니다.\n\n따라서 커버링에서는 대형 폐기물 수거는 진행되지 않는다는 점 참고 부탁드리며, \n빼기 앱을 통해 신청하신 수거 주문건의 결제 상태, 주문 내역 등 관련 문의는 커버링이 아닌\n''빼기'' 고객센터를 통해서 확인 및 안내가 가능한 점 양해 부탁드립니다.\n\n번거로우시겠지만, 빠른 해결을 위해 관련 내용은 빼기 측 고객센터로 문의해 주시면 감사드리겠습니다.', '파트너앱/시스템/계정', 1),
('빼기_주문', E'안녕하세요, 커버링 입니다.\n\n전달 주신 수거 주문번호는 빼기 측 주문번호로 확인됩니다.\n해당 건과 관련하여 저희측에서는 확인이 어려워 번거로우시더라도 빼기 측 고객센터로 문의 부탁드립니다.\n\n감사합니다.', '파트너앱/시스템/계정', 2),
('업데이트_카드재등록', E'안녕하세요, 커버링 입니다.\n\n고객님, 최근 서비스 업데이트 진행하면서 pg사가 변경되었습니다.\n\n**pg사란? 카드 결제를 진행하실 수 있도록 제공하는 업체 입니다.\n\npg사가 변경되면 고객님들의 결제 정보, 개인정보 등 보안이 필요한 정보들이 존재하여, 자동으로 값이 이전되지 않습니다.\n따라서, 기존 등록하신 카드 정보는 삭제되고 (보안을 위해 필요한 과정) 카드 재등록이 필요합니다.\n번거로우시더라도 카드 재등록 하여 이용을 부탁드립니다.', '파트너앱/시스템/계정', 3),
('등급제', E'안녕하세요, 커버링 입니다.\n\n커버링의 회원 등급은 최근 71일(약 10주) 동안의 결제 완료된 수거 주문 수를 기준으로 산정됩니다.\n\n등급은 매주 월요일 오후 4시에 자동으로 확정되며,\n등급이 오르지 않는 경우에는 최근 71일간의 수거 완료 주문 수를 확인해 보시기 바랍니다.\n\n** 앱 내에서 보이는 "OO등급까지 N회 남았습니다" 문구에 표시된 회차 기준은,\n현재 시점부터 다음 등급 산정일(다음 주 월요일)까지의 기간을 기준으로 계산됩니다.\n\n이용에 참고 부탁드립니다.\n\n감사합니다.', '파트너앱/시스템/계정', 4),
('계정이전', E'안녕하세요, 커버링 입니다.\n\n번호가 변경되어 계정 이전이 필요하실까요?\n아래 내용 작성해 주시면 계정 이전 후 안내드리겠습니다.\n\n\n기존에 이용하셨던 번호 : \n기존 주소 & 출입방법 : \n신규 이용 번호 : \n\n\n*주의사항\n1. 신규 번호로 가입하셨다면 탈퇴해 주세요\n2. 기존 계정 로그아웃 해주세요\n\n\n요청주신 건은 데이터 이전 작업이 필요한 건으로,\n다소 시간이 소요되는 점 양해 부탁드립니다.', '파트너앱/시스템/계정', 5),
('신규쿠폰문의', E'안녕하세요, 커버링 입니다.\n\n문의주신 쿠폰은 "[WELCOME] 첫 회원가입 기본 요금 무료" 쿠폰을 말씀하시는 듯 합니다.\n해당 쿠폰은 신규 가입 고객님께 발급되는 혜택으로, 수거 신청 시 직접 쿠폰 적용해 주셔야 반영됩니다.\n참고로 해당 쿠폰은 수거 전체 금액이 아닌 ''기본 요금(배송비 개념)''에 한해 면제되는 부분으로, 이용에 혼동이 없으시기 바랍니다.\n\n또한 만료된 쿠폰은 재발급이 어려우며, 아래의 경우에는 쿠폰이 자동으로 발급되지 않는 점 참고 부탁드립니다.\n\n- 과거에 커버링을 탈퇴한 뒤 다시 가입하신 경우\n\n\n커버링에서는 기본요금 무료 쿠폰부터 등급별 할인 쿠폰까지 다양한 혜택을 제공하고 있습니다.\n앞으로도 고객님께서 커버링을 이용할수록 ''합리적이다'' 라는 생각이 드실 수 있도록 노력하겠습니다.\n\n감사합니다.', '파트너앱/시스템/계정', 6);
INSERT INTO macros (name, content, category, sort_order) VALUES
('상담종료', E'답변 드린 내용이 도움 되셨길 바라며,\n추가 문의 사항이 없으시다면 이번 상담은 종료하겠습니다.\n추후에 궁금한 사항이 있으시다면 종료된 채팅은 누락의 위험이 있어, 새로운 채팅을 통해 언제든 다시 문의 주시기 바랍니다 :)\n\n오늘도 행복한 하루 되세요!', '상담관리/계정', 1),
('중복문의', E'안녕하세요, 커버링 입니다.\n현재 동일한 내용으로 아래 채팅에서 상담 진행 중입니다.\n클릭하기\n\n동일 내용으로 중복 문의가 접수될 경우, 답변이 누락될 수 있어요.\n전달 드린 채팅에서 이어서 상담 진행해 드리겠습니다 :)\n\n감사합니다.', '상담관리/계정', 2),
('탈퇴경로', E'안녕하세요, 커버링 입니다.\n\n번거로우시겠지만 탈퇴는 고객님께서 직접 진행해 주셔야 하여 아래 경로로 안내드립니다.\n\n*[앱 → 내정보 → 내정보 설정 → 탈퇴하기]\n\n만일 진행중인 주문건이 있을 경우에는 상태값이 "완료" 로 변경되어야 탈퇴 가능한 점 참고 부탁드립니다.', '상담관리/계정', 3),
('탈퇴완료', E'그동안 커버링 서비스를 이용해 주셔서 감사드립니다.\n추후 필요하실 때 다시 한번 찾아주세요 :)\n항상 행복 가득하시기 바라겠습니다.\n감사합니다.', '상담관리/계정', 4);
INSERT INTO macros (name, content, category, sort_order) VALUES
('명절_주문폭주', E'안녕하세요, 커버링 입니다.\n\n명절 기간 주문 폭주로 인해 일부 지역은 수거 일정이 다소 지연될 수 있습니다.\n최대한 빠르고 원활하게 수거 진행될 수 있도록 기사님들이 순차적으로 방문 중이니, 조금만 양해 부탁드립니다\n\n즐거운 추석 / 설날 보내시고, 풍성한 명절 되세요', '시즌/공휴일', 1),
('명절_수거휴무', E'안녕하세요, 커버링 입니다.\n\n설 연휴 수거 일정 관련하여 지역별로 안내 드립니다.\n\n\n[공통 안내]\n휴무일: 2025년 2월 17일\n수거 마감: 2월 16일 오후 10시까지 신청된 건에 한해 수거 진행\n이후 신청 건: 2월 18일 오후 10시부터 순차 수거 진행\n\n[설 연휴 기간 정상 운영 지역]\n서울, 인천, 고양, 수원, 화성, 오산, 남양주, 구리, 하남\n\n[설 연휴 기간 부분 운영 지역]\n부천, 안양, 군포, 의왕, 의정부: 2월 16일 / 2월 18일\n김포, 성남, 시흥: 2월 17일\n용인: 2월 18일\n\n\n연휴 기간에도 CS 문의는 정상 운영 되오니,\n궁금하신 사항은 언제든지 문의 주세요 :)', '시즌/공휴일', 2);
