-- ============================================
-- 매크로/템플릿 테이블 생성 + 시드 데이터
-- ============================================

CREATE TABLE IF NOT EXISTS macros (
  id SERIAL PRIMARY KEY,
  name TEXT NOT NULL,
  content TEXT NOT NULL,
  category TEXT DEFAULT '일반',
  sort_order INTEGER DEFAULT 0,
  is_active BOOLEAN DEFAULT true,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_macros_category ON macros(category);
CREATE INDEX IF NOT EXISTS idx_macros_active ON macros(is_active);

ALTER TABLE macros ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Allow all for macros" ON macros FOR ALL USING (true) WITH CHECK (true);

